def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.dml.color import RGBColor
    import os
    # Define what is considered 'light blue' in RGB
    LIGHT_BLUE_RGB = [
        (173, 216, 230), # LightBlue
        (135, 206, 250), # LightSkyBlue
        (176, 224, 230), # PowderBlue
        (0, 191, 255),   # DeepSkyBlue
        (135, 206, 235)  # SkyBlue
    ]
    TOLERANCE = 20 # Accept a range for minor agent imprecision

    if not os.path.exists(modified_ppt_path):
        return ("Modified PPT file not found.", 0.0)
    try:
        prs = Presentation(modified_ppt_path)
        slide = prs.slides[2] # slide 3 is index 2
        bg = slide.background
        # Try to get fill color
        if not bg.fill or bg.fill.type != 1:
            return ("Slide 3 background does not have a solid fill.", 0.0)
        color = bg.fill.fore_color.rgb
        if color is None:
            return ("Slide 3 background color not detected.", 0.0)
        r, g, b = color[0], color[1], color[2]
        for lbr, lbg, lbb in LIGHT_BLUE_RGB:
            if abs(r-lbr)<=TOLERANCE and abs(g-lbg)<=TOLERANCE and abs(b-lbb)<=TOLERANCE:
                return ("Slide 3 background color is light blue.", 1.0)
        return (f"Slide 3 background color is not light blue. Detected RGB: ({r},{g},{b})", 0.0)
    except Exception as e:
        return (f"Error checking background color: {e}", 0.0)

def compute_score() -> tuple[str, float]:
    # No unwanted changes should be made to the slides.
    from pptx import Presentation
    from pptx.enum.shapes import MSO_SHAPE_TYPE

    pres_original = Presentation(original_ppt_path)
    pres_modified = Presentation(modified_ppt_path)
    slide_idx = 2
    slide_original = pres_original.slides[slide_idx]
    slide_modified = pres_modified.slides[slide_idx]

    differences = []

    # Check if the number of shapes is the same
    if len(slide_original.shapes) != len(slide_modified.shapes):
        differences.append(f"Shape count mismatch: original has {len(slide_original.shapes)}, modified has {len(slide_modified.shapes)}")
        return ('; '.join(differences), 0.0)

    # Compare each shape
    for idx, (shape_orig, shape_mod) in enumerate(zip(slide_original.shapes, slide_modified.shapes)):
        # Check shape type
        if shape_orig.shape_type != shape_mod.shape_type:
            differences.append(f"Shape {idx}: type mismatch ({shape_orig.shape_type} vs {shape_mod.shape_type})")
            continue

        # Check shape position and size
        if shape_orig.left != shape_mod.left:
            differences.append(f"Shape {idx}: left position differs ({shape_orig.left} vs {shape_mod.left})")
        if shape_orig.top != shape_mod.top:
            differences.append(f"Shape {idx}: top position differs ({shape_orig.top} vs {shape_mod.top})")
        if shape_orig.width != shape_mod.width:
            differences.append(f"Shape {idx}: width differs ({shape_orig.width} vs {shape_mod.width})")
        if shape_orig.height != shape_mod.height:
            differences.append(f"Shape {idx}: height differs ({shape_orig.height} vs {shape_mod.height})")

        # Check text content if shape has text
        if shape_orig.has_text_frame and shape_mod.has_text_frame:
            text_orig = shape_orig.text_frame.text
            text_mod = shape_mod.text_frame.text
            if text_orig != text_mod:
                differences.append(f"Shape {idx}: text differs ('{text_orig}' vs '{text_mod}')")

            # Check paragraph count
            if len(shape_orig.text_frame.paragraphs) != len(shape_mod.text_frame.paragraphs):
                differences.append(f"Shape {idx}: paragraph count differs")
        elif shape_orig.has_text_frame != shape_mod.has_text_frame:
            differences.append(f"Shape {idx}: text frame presence mismatch")

        # Check if shape is a table
        if shape_orig.shape_type == MSO_SHAPE_TYPE.TABLE and shape_mod.shape_type == MSO_SHAPE_TYPE.TABLE:
            table_orig = shape_orig.table
            table_mod = shape_mod.table

            if len(table_orig.rows) != len(table_mod.rows):
                differences.append(f"Shape {idx}: table row count differs ({len(table_orig.rows)} vs {len(table_mod.rows)})")
            if len(table_orig.columns) != len(table_mod.columns):
                differences.append(f"Shape {idx}: table column count differs ({len(table_orig.columns)} vs {len(table_mod.columns)})")

            # Compare table cell contents
            for row_idx, (row_orig, row_mod) in enumerate(zip(table_orig.rows, table_mod.rows)):
                for col_idx, (cell_orig, cell_mod) in enumerate(zip(row_orig.cells, row_mod.cells)):
                    if cell_orig.text != cell_mod.text:
                        differences.append(f"Shape {idx}: table cell ({row_idx},{col_idx}) text differs ('{cell_orig.text}' vs '{cell_mod.text}')")

        # Check if shape is a group
        if shape_orig.shape_type == MSO_SHAPE_TYPE.GROUP and shape_mod.shape_type == MSO_SHAPE_TYPE.GROUP:
            if len(shape_orig.shapes) != len(shape_mod.shapes):
                differences.append(f"Shape {idx}: group shape count differs ({len(shape_orig.shapes)} vs {len(shape_mod.shapes)})")

    if differences:
        return ('; '.join(differences[:5]), 0.0)  # Return first 5 differences to avoid overly long messages

    return ('No differences found', 1.0)

